        ],
    )
    .unwrap_or_default();
    let remote = git_stdout(
        repo_root,
        &["for-each-ref", "--format=%(refname)", "refs/remotes"],
    )
    .unwrap_or_default();

    let mut refs = local
        .lines()
        .chain(remote.lines())
        .map(str::trim)
        .filter(|line| line.contains("/opensession/branches/"))
