            }

            CleanupDoctorStatus {
                level: CleanupDoctorLevel::Warn,
                detail: format!(
                    "partially configured provider={} janitor={} provider_template={}",
                    config.provider.as_str(),
                    if janitor_present { "present" } else { "missing" },
                    if provider_ready { "ready" } else { "missing" }
                ),
                hint: Some("run `opensession cleanup init --provider auto` to repair cleanup automation".to_string()),
            }
        }
        Ok(None) => CleanupDoctorStatus {
            level: CleanupDoctorLevel::Warn,
            detail: "not configured".to_string(),
