    let _ = init_cleanup(
        repo_root,
        InitRequest {
            provider: CleanupInitProvider::Auto,
            remote: remote.to_string(),
            hidden_ttl_days: DEFAULT_TTL_DAYS,
            artifact_ttl_days: DEFAULT_TTL_DAYS,
            yes: true,
            json: false,
            silent: true,
