}

fn prompt_confirmation(prompt: &str) -> Result<()> {
    eprint!("{prompt}");
    io::stderr().flush().ok();

    let mut line = String::new();
    io::stdin()
        .read_line(&mut line)
        .context("read cleanup confirmation")?;
    if parse_confirmation(&line) {
        return Ok(());
    }

    bail!("cleanup init cancelled by user")
}

fn parse_confirmation(raw: &str) -> bool {
