            fs::read_to_string(&paths.gitlab_ci)
                .map(|body| {
                    body.contains(GITLAB_MARKER_START)
                        && body.contains(GITLAB_MARKER_END)
                        && body.contains(GITLAB_CLEANUP_TEMPLATE_INCLUDE)
